export function ranNum(length){if(length<=0)return 0;let timestamp=Date.now().toString(),timestampLength=timestamp.length;if(length<=timestampLength)return parseInt(timestamp.slice(0,length),10);let randomPartLength=length-timestampLength,digits=Array(randomPartLength);for(let i=0;i<randomPartLength;i++)digits[i]=Math.floor(10*Math.random());let result=timestamp+digits.join("");return length>16?result.slice(0,length):parseInt(result.slice(0,length),10)}